// ننتظر حتى ينتهي الـ ERPNext من تحميل محتويات صفحة الـ DOM بالكامل 
document.addEventListener("DOMContentLoaded", function() {

  // 1. منطق التبديل بين التبويبات (Tabs)
  const tabButtons = document.querySelectorAll('.block-root .tab-btn');
  const sections = document.querySelectorAll('.block-root .section');

  tabButtons.forEach(button => {
    button.addEventListener('click', function() {
      const targetTab = this.getAttribute('data-tab');

      // إخفاء كل السكاشن
      sections.forEach(sec => sec.classList.remove('visible'));

      // إلغاء كلاس النشاط من الأزرار
      tabButtons.forEach(btn => btn.classList.remove('active'));

      // إظهار السكشن المختار
      const targetSection = document.getElementById('sec-' + targetTab);
      if (targetSection) {
        targetSection.classList.add('visible');
      }

      // تفعيل الزر المضغوط
      this.classList.add('active');
    });
  });

  // 2. معالجة أحداث الأزرار الفرعية (Actions) والتواصل مع ERPNext
  // زر إضافة نشاط جديد بالأعلى
  const addBtn = document.getElementById('btn-add-activity');
  if (addBtn) {
    addBtn.addEventListener('click', function() {
      // إذا كنت تستخدم الحوارات السريعة في ERPNext، يمكنك استدعاء frappe.new_doc هنا
      if (typeof frappe !== 'undefined') {
        frappe.new_doc('Cultural Activity'); // قم بتغيير اسم الـ DocType لما يناسب نظامك
      } else {
        console.log('طلب إضافة نشاط جديد');
      }
    });
  }

  // أزرار العرض السريع داخل القوائم والجدول
  const actionButtons = document.querySelectorAll('.block-root .quick-action');
  actionButtons.forEach(btn => {
    btn.addEventListener('click', function() {
      const actionType = this.getAttribute('data-action');
      
      if (typeof frappe !== 'undefined') {
        // مثال: التوجيه لـ DocType معين عند الضغط على أزرار الجدول في ERPNext
        frappe.msgprint(__('تم اختيار الإجراء: ') + actionType);
      } else {
        console.log('Action triggered:', actionType);
      }
    });
  });

});

style:
/* إخفاء نصوص القراءة الآلية فقط */
.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
}

/* إعدادات خطوط والاتجاه العام للبلوك */
* { 
  box-sizing: border-box; 
  margin: 0; 
  padding: 0; 
}

.block-root { 
  direction: rtl; 
  font-family: var(--font-sans), sans-serif; 
  padding: 1rem; 
}

.block-header { 
  display: flex; 
  align-items: center; 
  justify-content: space-between; 
  margin-bottom: 1.25rem; 
}

.block-title { 
  font-size: 18px; 
  font-weight: 600; 
  color: var(--color-text-primary, #111827); 
}

.block-subtitle { 
  font-size: 13px; 
  color: var(--color-text-secondary, #6b7280); 
  margin-top: 2px; 
}

/* أزرار التبويبات (Tabs) */
.tab-row { 
  display: flex; 
  gap: 8px; 
  margin-bottom: 1.25rem; 
  flex-wrap: wrap; 
}

.tab-btn { 
  font-size: 13px; 
  padding: 8px 16px; 
  border-radius: var(--border-radius-md, 6px); 
  border: 0.5px solid var(--color-border-tertiary, #e5e7eb); 
  background: transparent; 
  color: var(--color-text-secondary, #6b7280); 
  cursor: pointer; 
  transition: all 0.15s ease-in-out; 
}

.tab-btn.active { 
  background: var(--color-background-secondary, #f3f4f6); 
  color: var(--color-text-primary, #111827); 
  border-color: var(--color-border-primary, #9ca3af); 
  font-weight: 500; 
}

.tab-btn:hover:not(.active) { 
  background: var(--color-background-secondary, #f3f4f6); 
}

/* الأقسام المخفية والظاهرة */
.section { 
  display: none; 
}

.section.visible { 
  display: block; 
}

/* لوحة الإحصائيات السريعة */
.stats-grid { 
  display: grid; 
  grid-template-columns: repeat(auto-fit, minmax(160px, 1fr)); 
  gap: 12px; 
  margin-bottom: 1.5rem; 
}

.stat-card { 
  background: var(--color-background-secondary, #f9fafb); 
  border-radius: var(--border-radius-md, 6px); 
  padding: 1rem; 
  border: 1px solid var(--color-border-tertiary, #f3f4f6);
}

.stat-label { 
  font-size: 12px; 
  color: var(--color-text-secondary, #6b7280); 
  margin-bottom: 6px; 
}

.stat-value { 
  font-size: 24px; 
  font-weight: 600; 
  color: var(--color-text-primary, #111827); 
}

.stat-change { 
  font-size: 11px; 
  margin-top: 4px; 
}

.stat-change-neutral {
  font-size: 11px; 
  margin-top: 4px;
  color: var(--color-text-secondary, #9ca3af);
}

.up { color: #1D9E75; } 
.down { color: #D85A30; }

/* تصميم قائمة البطاقات (الكادر الدعوي) */
.card-list { 
  display: flex; 
  flex-direction: column; 
  gap: 10px; 
}

.card-item { 
  background: var(--color-background-primary, #ffffff); 
  border: 0.5px solid var(--color-border-tertiary, #e5e7eb); 
  border-radius: var(--border-radius-lg, 8px); 
  padding: 1rem; 
  display: flex; 
  align-items: center; 
  gap: 14px; 
  transition: border-color 0.15s; 
}

.card-item:hover { 
  border-color: var(--color-border-secondary, #d1d5db); 
}

.card-avatar { 
  width: 40px; 
  height: 40px; 
  border-radius: 50%; 
  display: flex; 
  align-items: center; 
  justify-content: center; 
  font-size: 14px; 
  font-weight: 500; 
  flex-shrink: 0; 
}

.av-blue { background: #E6F1FB; color: #185FA5; }
.av-teal { background: #E1F5EE; color: #0F6E56; }
.av-amber { background: #FAEEDA; color: #854F0B; }
.av-coral { background: #FAECE7; color: #993C1D; }

.card-info { 
  flex: 1; 
  min-width: 0; 
}

.card-name { 
  font-size: 14px; 
  font-weight: 500; 
  color: var(--color-text-primary, #111827); 
}

.card-meta { 
  font-size: 12px; 
  color: var(--color-text-secondary, #6b7280); 
  margin-top: 2px; 
  white-space: nowrap; 
  overflow: hidden; 
  text-overflow: ellipsis; 
}

.card-badge { 
  font-size: 11px; 
  padding: 4px 12px; 
  border-radius: var(--border-radius-md, 6px); 
  flex-shrink: 0; 
}

.badge-success { background: #E1F5EE; color: #0F6E56; }
.badge-warn { background: #FAEEDA; color: #854F0B; }
.badge-info { background: #E6F1FB; color: #185FA5; }
.badge-muted { background: var(--color-background-secondary, #f3f4f6); color: var(--color-text-secondary, #6b7280); }

/* القائمة السريعة للأنشطة */
.quick-list { 
  display: flex; 
  flex-direction: column; 
}

.quick-item { 
  display: flex; 
  align-items: center; 
  gap: 12px; 
  padding: 12px 0; 
  border-bottom: 0.5px solid var(--color-border-tertiary, #e5e7eb); 
}

.quick-item:last-child { 
  border-bottom: none; 
}

.quick-icon { 
  width: 34px; 
  height: 34px; 
  border-radius: var(--border-radius-md, 6px); 
  display: flex; 
  align-items: center; 
  justify-content: center; 
  flex-shrink: 0; 
}

.quick-text { 
  flex: 1; 
  font-size: 13px; 
  color: var(--color-text-primary, #111827); 
}

.quick-detail { 
  font-size: 12px; 
  color: var(--color-text-secondary, #6b7280); 
}

.quick-action { 
  font-size: 11px; 
  color: var(--color-text-secondary, #6b7280); 
  padding: 4px 12px; 
  border: 0.5px solid var(--color-border-tertiary, #e5e7eb); 
  border-radius: var(--border-radius-md, 6px); 
  cursor: pointer; 
  background: transparent; 
  transition: background 0.15s; 
  white-space: nowrap; 
}

.quick-action:hover { 
  background: var(--color-background-secondary, #f3f4f6); 
}

/* جدول المراكز */
.mini-table { 
  width: 100%; 
  border-collapse: collapse; 
  font-size: 13px; 
}

.mini-table th { 
  text-align: right; 
  font-weight: 500; 
  font-size: 12px; 
  color: var(--color-text-secondary, #6b7280); 
  padding: 0 0 10px; 
  border-bottom: 0.5px solid var(--color-border-tertiary, #e5e7eb); 
}

.mini-table td { 
  padding: 12px 0; 
  border-bottom: 0.5px solid var(--color-border-tertiary, #e5e7eb); 
  color: var(--color-text-primary, #111827); 
  vertical-align: middle; 
}

.mini-table tr:last-child td { 
  border-bottom: none; 
}

.mini-table td:last-child, 
.mini-table th:last-child { 
  text-align: left; 
}

.product-title { font-weight: 500; }
.sku { color: var(--color-text-secondary, #6b7280); font-size: 11px; }

/* نقاط المراقبة الملونة */
.dot { 
  width: 8px; 
  height: 8px; 
  border-radius: 50%; 
  display: inline-block; 
  margin-left: 6px; 
  vertical-align: middle; 
}

.dot-green { background: #1D9E75; } 
.dot-amber { background: #BA7517; } 
.dot-red { background: #D85A30; }

/* أزرار الإجراء الرئيسية الأعلى */
.add-btn { 
  display: flex; 
  align-items: center; 
  gap: 6px; 
  font-size: 13px; 
  padding: 8px 16px; 
  border-radius: var(--border-radius-md, 6px); 
  border: 0.5px solid var(--color-border-secondary, #d1d5db); 
  background: transparent; 
  color: var(--color-text-primary, #111827); 
  cursor: pointer; 
  transition: background 0.15s; 
}

.add-btn:hover { 
  background: var(--color-background-secondary, #f3f4f6); 
}
